// InAppNudge One in-app nudge for the requested context.
//
// Server returns AT MOST ONE per “GET ?context=“ call (cardinality
// cap defended in the endpoint logic, not just the schema).
type InAppNudge struct {
	// AnchorTarget Where on the nav bar the tooltip points. Mobile resolves to TutorialContext registered ID via anchor_target_to_tutorial_id helper. tab_settings is desktop-only — server suppresses this anchor for phone clients.
	AnchorTarget string `json:"anchor_target"`

	// Context Canonical context this nudge fires in. Echoes the request param so mobile can verify the response matches the request (defense against stale cached responses across context transitions).
	Context string `json:"context"`

	// CooldownSeconds Mobile MAY use this to throttle re-poll within the same context. Server enforces cooldown at the eligibility-query layer; this is an advisory for client-side polling.
	CooldownSeconds *int `json:"cooldown_seconds,omitempty"`

	// Data Structured data for mobile i18n interpolation.
	//
	// Each nudge_type defines its own keys. Mobile resolves
	// ``i18n_key`` (e.g. ``in_app_nudge_review_backlog_title``) with
	// these values interpolated.
	//
	// Examples:
	//   review_backlog_idle: {"due_count": 15}
	//   try_scenarios_first_time: {"tracked_word_count": 47}
	//   roadmap_completionist_explore: {"lessons_completed": 12}
	//   convo_user_try_reading: {"conversation_count": 3}
	Data *InAppNudgeData `json:"data,omitempty"`

	// DeepLink kielo://path the mobile CTA tap routes to. Resolved by the existing notificationRouting.parseRecommendationDeepLink parser. Routes to existing screens only — no new mobile navigation required for Arc G3.
	DeepLink string `json:"deep_link"`

	// ExpiresAt Optional. If set, mobile MUST stop rendering after this timestamp (covers e.g. flash-sale-style nudges). Not used by the 4 v1 nudges; reserved for future types.
	ExpiresAt *time.Time `json:"expires_at"`

	// NudgeId Stable per-(user, nudge_type, context) composite ID. Server generates deterministically from the composite PK so mobile can dedupe optimistically when the same nudge re-fires across polls. Used as the dismiss_id in POST state transitions.
	NudgeId uuid.UUID `json:"nudge_id"`

	// NudgeType Canonical nudge category from Arc G1 SoT. Mobile uses this as the i18n key prefix (e.g. nudge_type='review_backlog_idle' → i18n key 'in_app_nudge_review_backlog_title'). Pinned by V117 CHECK constraint + cross-language SoT parity.
	NudgeType string `json:"nudge_type"`

	// RequiredFeatureType Optional cross-check when anchor_target='tab_quick_feature'. Values: 'news' | 'ktv' | 'juka'. Mobile suppresses render if useLastUsedFeature() doesn't match. Defends against the quick-feature slot-swap race (Arc G1 brittleness defense #1).
	RequiredFeatureType *string `json:"required_feature_type"`
}

// InAppNudgeData Structured data for mobile i18n interpolation.
//
// Each nudge_type defines its own keys. Mobile resolves
// “i18n_key“ (e.g. “in_app_nudge_review_backlog_title“) with
// these values interpolated.
//
// Examples:
//
//	review_backlog_idle: {"due_count": 15}
//	try_scenarios_first_time: {"tracked_word_count": 47}
//	roadmap_completionist_explore: {"lessons_completed": 12}
//	convo_user_try_reading: {"conversation_count": 3}
type InAppNudgeData map[string]interface{}

// InAppNudgeStateTransition Body shape for
// “POST /internal/me/in-app-nudges/{nudge_id}/state“.
//
// Mobile sends one of four lifecycle transitions:
//
//   - 'seen' — render fire (bumps show_count + stamps last_shown_at)
//   - 'dismissed' — user explicitly closed (stops eligibility forever
//     unless server-side ETag invalidates)
//   - 'snoozed' — "remind me later"; re-eligible after snoozed_until
//   - 'acted_on' — user tapped CTA (stops eligibility forever)
//
// Each transition writes to “users.in_app_nudge_state“ per the
// canonical lifecycle columns defined in V117.
type InAppNudgeStateTransition struct {
	// SnoozedUntil Required when transition='snoozed'. Ignored for other transitions. Server clamps to max 7 days from now.
	SnoozedUntil *time.Time `json:"snoozed_until"`

	// Transition One of: 'seen' | 'dismissed' | 'snoozed' | 'acted_on'. Validated server-side; unknown values rejected as 400.
	Transition string `json:"transition"`
}

